import React, { useState, useEffect, useMemo } from 'react';

// Import types
import { Product, CartItem, Order, User, Customer, WithdrawalRequest, FaqItem, SiteSettings, Category, Ticket, TicketMessage, Coupon, Supplier, SupplierWithdrawal, AppNotification, AdminView } from './types';

// Import mock data
import { mockProducts, mockOrders, mockUsers, mockCustomers, mockWithdrawalRequests, mockFaqItems, mockSiteSettings, mockCategories, mockTickets, mockCoupons, mockSuppliers, mockSupplierWithdrawals, mockSystemNotifications } from './data/mockData';

// Import components (Updated Paths)
import Header from './components/common/Header';
import BottomNav from './components/common/BottomNav';
import ProductsPage from './components/customer/ProductsPage';
import OrdersPage from './components/customer/OrdersPage';
import AccountPage from './components/customer/AccountPage';
import ProductDetailsPage from './components/customer/ProductDetailsPage';
import CartPage from './components/customer/CartPage';
import CheckoutPage from './components/customer/CheckoutPage';
import OrderDetailsPage from './components/customer/OrderDetailsPage';
import AccountSubPage from './components/customer/AccountSubPage';
import WithdrawalsPage from './components/customer/WithdrawalsPage';
import StatisticsPage from './components/customer/StatisticsPage';
import CategoriesPage from './components/customer/CategoriesPage';
import TicketChatModal from './components/customer/TicketChatModal';
import MyTicketsPage from './components/customer/MyTicketsPage';

export type Page = 'products' | 'orders' | 'account' | 'productDetails' | 'cart' | 'checkout' | 'orderDetails' | 'accountSubPage' | 'withdrawals' | 'statistics' | 'categories' | 'ticketChat' | 'tickets';
export type MainView = 'products' | 'orders' | 'account' | 'tickets';
export type AccountSubPageView = 'editProfile' | 'savedProducts' | 'customerDetails' | 'notifications' | 'instructions' | 'adminDashboard' | 'privacyPolicy' | 'termsAndConditions' | 'serviceFees' | 'myTickets';
export type SelectedStatus = Order['status'] | 'all' | 'cancelled_rejected' | 'prepared' | 'postponed' | 'partially_delivered' | null;

export interface HeaderConfig {
    title: string;
    showBack: boolean;
    onBack?: () => void;
    showAddProduct?: boolean;
    onAddProduct?: () => void;
    showProductStats?: boolean;
    onProductStatsClick?: () => void;
    showAddTicket?: boolean;
    onAddTicket?: () => void;
}

const App: React.FC = () => {
    const [currentUser, setCurrentUser] = useState<User | null>(mockUsers[2]);
    const [products, setProducts] = useState<Product[]>([]);
    const [orders, setOrders] = useState<Order[]>([]);
    const [users, setUsers] = useState<User[]>([]);
    const [customers, setCustomers] = useState<Customer[]>([]);
    const [withdrawalRequests, setWithdrawalRequests] = useState<WithdrawalRequest[]>([]);
    const [faqItems, setFaqItems] = useState<FaqItem[]>([]);
    const [siteSettings, setSiteSettings] = useState<SiteSettings>(mockSiteSettings);
    const [categories, setCategories] = useState<Category[]>([]);
    const [tickets, setTickets] = useState<Ticket[]>([]);
    const [coupons, setCoupons] = useState<Coupon[]>([]);
    const [suppliers, setSuppliers] = useState<Supplier[]>([]); 
    const [supplierWithdrawals, setSupplierWithdrawals] = useState<SupplierWithdrawal[]>([]); // New State
    const [systemNotifications, setSystemNotifications] = useState<AppNotification[]>([]); // New State for System Notifications
    const [isLoadingProducts, setIsLoadingProducts] = useState(true);

    const [page, setPage] = useState<Page>('products');
    const [mainView, setMainView] = useState<MainView>('products');
    const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
    const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
    const [accountSubPageView, setAccountSubPageView] = useState<AccountSubPageView>('editProfile');
    const [checkoutStep, setCheckoutStep] = useState(1);
    const [pageHistory, setPageHistory] = useState<Page[]>(['products']);
    const [notifications, setNotifications] = useState<{ id: number, message: string }[]>([]);
    const [selectedCategory, setSelectedCategory] = useState<Category | null>(null);
    const [selectedOrderStatus, setSelectedOrderStatus] = useState<SelectedStatus>(null);
    const [headerConfig, setHeaderConfig] = useState<HeaderConfig | null>(null);
    const [isTicketChatModalOpen, setIsTicketChatModalOpen] = useState(false);
    const [selectedTicketThread, setSelectedTicketThread] = useState<Ticket | null>(null);
    const [adminView, setAdminView] = useState<AdminView>('dashboard'); // Lifted Admin State

    const [cartItems, setCartItems] = useState<CartItem[]>([]);
    const [savedProductIds, setSavedProductIds] = useState<string[]>([]);

    const [isDarkMode, setIsDarkMode] = useState(() => {
        const savedTheme = localStorage.getItem('theme');
        return savedTheme === 'dark';
    });

    useEffect(() => {
        if (isDarkMode) {
            document.documentElement.classList.add('dark');
            localStorage.setItem('theme', 'dark');
        } else {
            document.documentElement.classList.remove('dark');
            localStorage.setItem('theme', 'light');
        }
    }, [isDarkMode]);

    const toggleDarkMode = () => {
        setIsDarkMode(prevMode => !prevMode);
    };

    useEffect(() => {
        setTimeout(() => {
            setProducts(mockProducts);
            setOrders(mockOrders);
            setUsers(mockUsers);
            setCustomers(mockCustomers);
            setWithdrawalRequests(mockWithdrawalRequests);
            setFaqItems(mockFaqItems);
            setSiteSettings(mockSiteSettings);
            setCategories(mockCategories);
            setTickets(mockTickets);
            setCoupons(mockCoupons);
            setSuppliers(mockSuppliers); 
            setSupplierWithdrawals(mockSupplierWithdrawals); // Initialize
            setSystemNotifications(mockSystemNotifications); // Initialize
            setIsLoadingProducts(false);
        }, 1000);
    }, []);

    useEffect(() => {
        // Sync selected ticket thread with the main tickets array to keep the modal updated
        if (selectedTicketThread) {
            const updatedThread = tickets.find(t => t.id === selectedTicketThread.id);
            if (updatedThread) {
                // Deep comparison to prevent infinite re-renders
                if (JSON.stringify(updatedThread) !== JSON.stringify(selectedTicketThread)) {
                    setSelectedTicketThread(updatedThread);
                }
            } else {
                // Ticket was deleted or is no longer available, close modal
                setIsTicketChatModalOpen(false);
                setSelectedTicketThread(null);
            }
        }
    }, [tickets, selectedTicketThread]);

    const addNotification = (message: string) => {
        const newId = Date.now();
        setNotifications(prev => [...prev, { id: newId, message }]);
        setTimeout(() => {
            setNotifications(prev => prev.filter(n => n.id !== newId));
        }, 3000); 
    };

    const handleMarkSystemNotificationAsRead = (id: string) => {
        setSystemNotifications(prev => prev.map(n => n.id === id ? { ...n, isRead: true } : n));
    };

    const navigateTo = (newPage: Page) => {
        setPageHistory(prev => [...prev, page]);
        setPage(newPage);
    };

    const handleBack = () => {
        if (headerConfig?.showBack && headerConfig.onBack) {
            headerConfig.onBack();
            return;
        }
        if (page === 'products' && selectedCategory) {
            setSelectedCategory(null);
            return;
        }
        if (page === 'orders' && selectedOrderStatus) {
            setSelectedOrderStatus(null);
            return;
        }
        const lastPage = pageHistory[pageHistory.length - 1] || 'products';
        setPageHistory(prev => prev.slice(0, -1));
        setPage(lastPage);
    };

    const handleMainViewChange = (view: MainView) => {
        if (view === 'products') {
            setSelectedCategory(null);
        }
        if (view !== 'orders') {
            setSelectedOrderStatus(null);
        }
        setMainView(view);
        navigateTo(view as Page);
    };

    const handleCategorySelect = (category: Category) => {
        if (category.name === 'الكل') {
            setSelectedCategory(null);
        } else {
            setSelectedCategory(category);
        }
    };

    const handleCategorySelectForPage = (category: Category) => {
        if (category.name === 'الكل') {
            setSelectedCategory(null);
        } else {
            setSelectedCategory(category);
        }
        setMainView('products'); 
        navigateTo('products');
