    }

    const handleOrderClick = (order: Order) => {
        setSelectedOrder(order);
        navigateTo('orderDetails');
    };

    const handleOrderConfirmed = (orderData: Omit<Order, 'id' | 'user_id' | 'date' | 'time' | 'status' | 'created_at'>) => {
        if (!currentUser) {
            addNotification("يجب تسجيل الدخول لإكمال الطلب.");
            return;
        }
        const newOrder: Order = {
            ...orderData,
            id: `order-${Date.now()}`,
            user_id: currentUser.id,
            status: 'under_implementation',
            date: new Date().toLocaleDateString('ar-IQ'),
            time: new Date().toLocaleTimeString('ar-IQ'),
            created_at: new Date().toISOString(),
        };
        setOrders(prev => [newOrder, ...prev]);
        setCartItems([]);
        setCheckoutStep(1);
        navigateTo('orders');
        addNotification("تم إرسال طلبك بنجاح!");
    };

    const handleAddCustomer = (customerData: Omit<Customer, 'id' | 'user_id'>) => {
        if (!currentUser) return null;
        const newCustomer: Customer = { ...customerData, id: `cust-${Date.now()}`, user_id: currentUser.id };
        setCustomers(prev => [newCustomer, ...prev]);
        addNotification('تمت إضافة الزبون بنجاح');
        return newCustomer;
    };

    const handleUpdateCustomer = (updatedCustomer: Customer) => {
        setCustomers(prev => prev.map(c => c.id === updatedCustomer.id ? { ...c, ...updatedCustomer } : c));
        addNotification('تم تحديث بيانات الزبون');
    };

    const handleDeleteCustomer = (customerId: string) => {
        if (window.confirm("هل أنت متأكد من حذف هذا الزبون؟")) {
            setCustomers(prev => prev.filter(c => c.id !== customerId));
            addNotification('تم حذف الزبون');
        }
    };

    const handleInitiateTicketThread = (order: Order, initialMessageText: string) => {
        if (!currentUser) {
            addNotification("يجب تسجيل الدخول لإرسال التذكرة.");
            return;
        }
        if (!initialMessageText.trim()) {
            addNotification("لا يمكن إرسال تذكرة فارغة.");
            return;
        }

        // Check if a ticket already exists for this order by the current user
        const existingTicket = tickets.find(
            (ticket) => ticket.order_id === order.id && ticket.user_id === currentUser.id
        );

        if (existingTicket) {
            // If ticket exists, add message to it and open the chat
            addNotification("توجد تذكرة سابقة لهذا الطلب، تم إضافة رسالتك.");
            // The handleAddTicketMessage function will also handle re-opening if it's resolved
            handleAddTicketMessage(existingTicket.id, initialMessageText.trim());
            handleOpenTicketChat(existingTicket); // Use the existing function to open the modal
        } else {
            // If no ticket exists, create a new one
            const newTicketMessage: TicketMessage = {
                id: `msg-${Date.now()}`,
                senderId: currentUser.id,
                senderName: currentUser.name,
                text: initialMessageText.trim(),
                timestamp: new Date().toISOString(),
            };

            const newTicketThread: Ticket = {
                id: `ticket-${Date.now()}`,
                order_id: order.id,
                user_id: currentUser.id,
                user_name: currentUser.name,
                customer_name: order.customer.name,
                status: 'pending',
                created_at: new Date().toISOString(),
                messages: [newTicketMessage],
            };
            setTickets(prev => [newTicketThread, ...prev]);
            addNotification("تم إرسال التذكرة بنجاح!");
            handleOpenTicketChat(newTicketThread); // Open the newly created ticket
        }
    };

    const handleAddTicketMessage = (threadId: string, text?: string, imageUrl?: string) => {
        if (!currentUser) {
            addNotification("يجب تسجيل الدخول لإرسال الرسالة.");
            return;
        }

        const newTicketMessage: TicketMessage = {
            id: `msg-${Date.now()}`,
            senderId: currentUser.id,
            senderName: currentUser.name,
            text: text,
            imageUrl: imageUrl,
            timestamp: new Date().toISOString(),
        };

        setTickets(prevTickets =>
            prevTickets.map(thread => {
                if (thread.id === threadId) {
                    // Re-open ticket if it was resolved and the message is from a non-admin user
                    const newStatus = (thread.status === 'resolved' && !currentUser.is_admin) ? 'pending' : thread.status;

                    if (newStatus === 'pending' && thread.status === 'resolved') {
                        addNotification("تمت إعادة فتح التذكرة.");
                    }

                    return { 
                        ...thread, 
                        messages: [...thread.messages, newTicketMessage],
                        status: newStatus 
                    };
                }
                return thread;
            })
        );
    };

    const onUpdateTicketThreadStatus = (ticketId: string, status: Ticket['status']) => {
        setTickets(prev => prev.map(r => r.id === ticketId ? { ...r, status } : r));
        addNotification("تم تحديث حالة التذكرة.");
