    // Logic to calculate unread tickets for the User
    // Determine unread tickets: If the last message in a thread is NOT from the current user, it's considered new/unread for them.
    const unreadTicketsCount = useMemo(() => {
        if (!currentUser) return 0;
        return userTickets.filter(ticket => {
            const lastMessage = ticket.messages[ticket.messages.length - 1];
            return lastMessage && lastMessage.senderId !== currentUser.id;
        }).length;
    }, [userTickets, currentUser]);

