export type AdminView = 'dashboard' | 'overview' | 'products' | 'orders' | 'users' | 'withdrawals' | 'settings' | 'userDetails' | 'tickets' | 'coupons' | 'notifications' | 'suppliers' | 'supplierDetails' | 'employees';

import React, { useState, useEffect, useMemo } from 'react';
import { Product, Category, Supplier } from '../../types';
import { PlusIcon, TrashIcon, XMarkIcon, CameraIcon, MinusIcon, CubesStackIcon, TagIcon } from '../common/icons'; // Import icons
import { HeaderConfig } from '../../App';

interface AdminProductEditPageProps {
  productToEdit?: Product | null;
  onSave: (product: Product | Omit<Product, 'id'>) => void;
  onCancel: () => void;
  onDeleteProduct: (productId: string) => void; 
  categories: Category[];
  suppliers: Supplier[]; 
  setHeaderConfig: (config: HeaderConfig | null) => void;
}

const AdminProductEditPage: React.FC<AdminProductEditPageProps> = ({ productToEdit, onSave, onCancel, onDeleteProduct, categories: dynamicCategories, suppliers, setHeaderConfig }) => {
  const [name, setName] = useState('');
  const [price, setPrice] = useState(0);
  const [minSellPrice, setMinSellPrice] = useState(0);
  const [maxSellPrice, setMaxSellPrice] = useState(0);
  const [supplierPrice, setSupplierPrice] = useState(0); 
  const [supplierId, setSupplierId] = useState(''); 
  const [promo, setPromo] = useState('');
  const [description, setDescription] = useState('');
  const [marketingDescription, setMarketingDescription] = useState('');
  const [imageUrls, setImageUrls] = useState<string[]>([]);
  // Single Inventory
  const [inventory, setInventory] = useState<{ size: string, stock: number }[]>([]);

  // New State for Sale Type
  const [saleType, setSaleType] = useState<'single' | 'series'>('single');

  // Series Specific State
  const [seriesCount, setSeriesCount] = useState(0);
  const [seriesSizes, setSeriesSizes] = useState('');
  const [seriesStock, setSeriesStock] = useState(0);

  const [category, setCategory] = useState('');
  const [subcategory, setSubcategory] = useState('');
  const [telegramUrl, setTelegramUrl] = useState('');
  const [detailsList, setDetailsList] = useState<{key: string, value: string}[]>([]);
  const [tags, setTags] = useState<string[]>([]);

  useEffect(() => {
    if (productToEdit) {
      setName(productToEdit.name);
      setPrice(productToEdit.price);
      setMinSellPrice(productToEdit.min_sell_price);
      setMaxSellPrice(productToEdit.max_sell_price);
      setSupplierPrice(productToEdit.supplierPrice || 0); 
      setSupplierId(productToEdit.supplierId || ''); 
      setPromo(productToEdit.promo);
      setDescription(productToEdit.description || '');
      setMarketingDescription(productToEdit.marketing_description || '');
      setImageUrls(productToEdit.image_urls || []);
      setInventory(productToEdit.inventory.length > 0 ? productToEdit.inventory : [{ size: '', stock: 0 }]); 
      setCategory(productToEdit.category || '');
      setSubcategory(productToEdit.subcategory || '');
      setTelegramUrl(productToEdit.telegramUrl || '');
      setTags(productToEdit.tags || []);

      // Sale Type Logic
      setSaleType(productToEdit.sale_type || 'single');
      if (productToEdit.sale_type === 'series' && productToEdit.series_info) {
          setSeriesCount(productToEdit.series_info.count);
          setSeriesSizes(productToEdit.series_info.sizes_description);
          setSeriesStock(productToEdit.series_info.stock);
      }

      // Convert details object to array
      if (productToEdit.details) {
          const dList = Object.entries(productToEdit.details).map(([key, value]) => ({ key, value }));
          setDetailsList(dList.length > 0 ? dList : [{key: '', value: ''}]);
      } else {
          setDetailsList([{key: '', value: ''}]);
      }

    } else {
      // Reset form for new product
      setName('');
      setPrice(0);
      setMinSellPrice(0);
      setMaxSellPrice(0);
      setSupplierPrice(0);
      setSupplierId('');
      setPromo('');
      setDescription('');
      setMarketingDescription('');
      setImageUrls([]);
      setInventory([{ size: '', stock: 0 }]); 
      setCategory('');
      setSubcategory('');
      setTelegramUrl('');
      setDetailsList([{key: '', value: ''}]);
      setTags([]);
      setSaleType('single');
      setSeriesCount(0);
      setSeriesSizes('');
      setSeriesStock(0);
    }
  }, [productToEdit]);

  useEffect(() => {
    setHeaderConfig({
        title: productToEdit ? 'تعديل المنتج' : 'إضافة منتج جديد',
        showBack: true,
        onBack: onCancel,
    });
    return () => setHeaderConfig(null);
  }, [productToEdit, onCancel, setHeaderConfig]);

  const handlePriceChange = (field: 'price' | 'min' | 'max', val: number) => {
    let newPrice = price;
    let newMin = minSellPrice;
    let newMax = maxSellPrice;

    if (field === 'price') { setPrice(val); newPrice = val; }
    if (field === 'min') { setMinSellPrice(val); newMin = val; }
    if (field === 'max') { setMaxSellPrice(val); newMax = val; }

    // Smart Promo Logic
    if (newPrice > 0 && newMin > 0) {
        const profit = newMin - newPrice;
        if (profit > 0) {
            let autoPromo = `اربح ${profit.toLocaleString()} د.ع`;
            if (newMax > newMin) {
                autoPromo += ' أو أكثر';
            }
            setPromo(autoPromo);
        }
    }
  };

  const handleInventoryChange = (index: number, field: 'size' | 'stock', value: string | number) => {
    const newInventory = [...inventory];
    newInventory[index] = { ...newInventory[index], [field]: value };
    setInventory(newInventory);
  };

  const handleQuantityChange = (index: number, delta: number) => {
    const newInventory = [...inventory];
    const currentStock = newInventory[index].stock || 0;
    const newStock = Math.max(0, currentStock + delta);
    newInventory[index] = { ...newInventory[index], stock: newStock };
    setInventory(newInventory);
  };


  const addInventoryItem = () => {
    setInventory([...inventory, { size: '', stock: 0 }]);
  };

  const removeInventoryItem = (index: number) => {
    if (inventory.length > 1) {
      setInventory(inventory.filter((_, i) => i !== index));
    } else {
      setInventory([{ size: '', stock: 0 }]);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        const reader = new FileReader();
        reader.onloadend = () => {
            setImageUrls(prev => [...prev, reader.result as string]);
        };
        reader.readAsDataURL(file);
    }
  };

  const handleRemoveImage = (indexToRemove: number) => {
    setImageUrls(prev => prev.filter((_, index) => index !== indexToRemove));
  }

  const handleDetailChange = (index: number, field: 'key' | 'value', value: string) => {
      const newList = [...detailsList];
      newList[index] = { ...newList[index], [field]: value };
      setDetailsList(newList);
  };

  const addDetailRow = () => {
      setDetailsList([...detailsList, { key: '', value: '' }]);
  };

  const removeDetailRow = (index: number) => {
      if (detailsList.length > 1) {
          setDetailsList(detailsList.filter((_, i) => i !== index));
      } else {
          setDetailsList([{ key: '', value: '' }]);
      }
  };

  const handleTagChange = (tag: string, checked: boolean) => {
      if (checked) {
          setTags(prev => [...prev, tag]);
      } else {
          setTags(prev => prev.filter(t => t !== tag));
      }
  };


  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Basic Validation
    if (!name || price <= 0 || imageUrls.length === 0 || !category) {
        alert('يرجى ملء الاسم، السعر، الفئة، وإضافة صورة واحدة على الأقل.');
        return;
    }

    if (minSellPrice <= price || maxSellPrice < minSellPrice) {
        alert('يرجى التأكد من منطقية الأسعار (سعر البيع > سعر التكلفة).');
        return;
    }

    // Specific Validation based on Sale Type
    if (saleType === 'single') {
        if (inventory.some(item => !item.size || item.stock < 0)) {
            alert('يرجى تعبئة تفاصيل القياسات والمخزون بشكل صحيح للمنتج المفرد.');
            return;
        }
    } else {
        if (seriesCount <= 0 || !seriesSizes || seriesStock < 0) {
            alert('يرجى تعبئة تفاصيل السيرية (العدد، القياسات، والمخزون) بشكل صحيح.');
            return;
        }
    }

    const detailsObject: Record<string, string> = {};
    detailsList.forEach(item => {
        if (item.key.trim() && item.value.trim()) {
            detailsObject[item.key.trim()] = item.value.trim();
        }
    });

    const productData: any = { 
        name, 
        brand: '', 
        price, 
        min_sell_price: minSellPrice, 
        max_sell_price: maxSellPrice,
        supplierPrice,
        supplierId,
        promo, 
        description, 
        marketing_description: marketingDescription,
        image_urls: imageUrls, 
        category, 
        subcategory,
        telegramUrl,
        details: Object.keys(detailsObject).length > 0 ? detailsObject : undefined,
        tags,
        sale_type: saleType
    };

    if (saleType === 'single') {
        productData.inventory = inventory;
        productData.series_info = undefined;
    } else {
        productData.inventory = []; // Empty inventory for series items
        productData.series_info = {
            count: seriesCount,
            sizes_description: seriesSizes,
            stock: seriesStock
        };
    }

    if (productToEdit) {
      onSave({ ...productData, id: productToEdit.id });
    } else {
      onSave(productData);
    }
  };

  const handleDeleteClick = () => {
    if (productToEdit && window.confirm(`هل أنت متأكد من حذف المنتج "${productToEdit.name}"؟`)) {
        onDeleteProduct(productToEdit.id);
        onCancel(); 
    }
  };

  const categoriesToDisplay = useMemo(() => {
      return dynamicCategories.filter(c => c.name !== 'الكل' && c.name !== 'جديد' && !c.parentId);
  }, [dynamicCategories]);

  const subcategoriesToDisplay = useMemo(() => {
      const selectedCat = dynamicCategories.find(c => c.name === category);
      if(!selectedCat) return [];
      return dynamicCategories.filter(c => c.parentId === selectedCat.id);
  }, [category, dynamicCategories]);

  return (
    <div className="p-4 dark:bg-slate-900 pb-24"> 
      <form onSubmit={handleSubmit} className="space-y-6"> 

        {/* Sale Type Selector - TOP */}
        <div className="p-4 bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm">
            <label className="text-sm font-bold text-gray-800 dark:text-gray-100 block text-right mb-3">نوع البيع</label>
            <div className="grid grid-cols-2 gap-3">
                <button
                    type="button"
                    onClick={() => setSaleType('single')}
                    className={`flex flex-col items-center justify-center p-4 rounded-xl border-2 transition-all ${saleType === 'single' ? 'border-primary bg-primary/5 text-primary' : 'border-gray-200 dark:border-gray-700 hover:border-gray-300 dark:hover:border-gray-600 text-gray-500'}`}
                >
                    <TagIcon className="w-6 h-6 mb-2" />
                    <span className="font-bold">بيع مفرد (بالقطعة)</span>
                </button>
                <button
                    type="button"
                    onClick={() => setSaleType('series')}
                    className={`flex flex-col items-center justify-center p-4 rounded-xl border-2 transition-all ${saleType === 'series' ? 'border-primary bg-primary/5 text-primary' : 'border-gray-200 dark:border-gray-700 hover:border-gray-300 dark:hover:border-gray-600 text-gray-500'}`}
                >
                    <CubesStackIcon className="w-6 h-6 mb-2" />
                    <span className="font-bold">بيع سيريات (بالشدة)</span>
                </button>
            </div>
        </div>

        {/* Image Upload Section */}
        <div className="p-4">
          <label className="text-sm font-semibold text-gray-600 dark:text-gray-400 block text-right mb-2">صور المنتج</label>
          <div className="grid grid-cols-3 gap-2">
              {imageUrls.map((url, index) => (
                  <div key={index} className="relative group aspect-square">
                      <img src={url} className="w-full h-full object-cover rounded-lg bg-gray-100 dark:bg-gray-700" loading="lazy" />
                      <button type="button" onClick={() => handleRemoveImage(index)} className="absolute top-1 right-1 bg-black/50 text-white rounded-full w-6 h-6 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                          <XMarkIcon className="w-4 h-4" />
                      </button>
                  </div>
              ))}
              {imageUrls.length < 5 && (
                  <label htmlFor="image-upload" className="flex justify-center items-center w-full h-full border-2 border-gray-300 border-dashed rounded-lg cursor-pointer bg-gray-50 hover:bg-gray-100 dark:bg-gray-800 dark:hover:bg-gray-700 aspect-square">
                      <div className="flex flex-col items-center justify-center text-center">
                          <CameraIcon className="w-8 h-8 text-gray-500" />
                          <p className="text-xs text-gray-500">رفع صورة</p>
                      </div>
                      <input id="image-upload" type="file" className="hidden" accept="image/png, image/jpeg" onChange={handleImageUpload} />
                  </label>
              )}
          </div>
        </div>

        {/* Basic Info */}
        <div className="p-4">
          <label className="text-sm font-semibold text-gray-600 dark:text-gray-400 block text-right mb-1">اسم المنتج</label>
          <input type="text" placeholder="عنوان المنتج" value={name} onChange={e => setName(e.target.value)} required className="w-full p-3 border dark:border-gray-700 rounded-lg text-right bg-white dark:bg-gray-800 dark:text-white" />
        </div>

        {/* Telegram Link */}
        <div className="p-4">
          <label className="text-sm font-semibold text-gray-600 dark:text-gray-400 block text-right mb-1">رابط تليكرام (اختياري)</label>
          <div className="relative">
             <input type="url" placeholder="https://t.me/..." value={telegramUrl} onChange={e => setTelegramUrl(e.target.value)} className="w-full p-3 pl-10 border dark:border-gray-700 rounded-lg text-right bg-white dark:bg-gray-800 dark:text-white" />
             <i className="fa-brands fa-telegram absolute left-3 top-1/2 -translate-y-1/2 text-blue-500 text-xl"></i>
          </div>
        </div>

        {/* Inventory Section (Conditional) */}
        {saleType === 'single' ? (
            // --- Single Item Inventory ---
            <div className="p-4 bg-gray-50 dark:bg-gray-800/50 rounded-xl border border-gray-200 dark:border-gray-700 mx-4">
               <div className="flex justify-between items-center mb-2">
                   <label className="text-sm font-bold text-gray-700 dark:text-gray-200">القياسات والكميات (للمفرد)</label>
                   <span className="text-xs text-gray-500">ادخل كل قياس على حدة</span>
               </div>
               <div className="space-y-3">
                  {inventory.map((item, index) => (
                      <div key={index} className="flex items-center gap-2">
                          <button type="button" onClick={() => removeInventoryItem(index)} className="text-red-500 disabled:opacity-50 disabled:cursor-not-allowed" disabled={inventory.length <= 1} aria-label="حذف القياس">
                            <TrashIcon />
                          </button>

                          <div className="flex items-center border border-gray-300 dark:border-gray-700 rounded-lg overflow-hidden flex-grow justify-between bg-white dark:bg-gray-800">
                            <button type="button" onClick={() => handleQuantityChange(index, 1)} className="p-2 text-primary dark:text-primary-light hover:bg-primary-light dark:hover:bg-primary/20">
                                <PlusIcon className="w-5 h-5"/>
                            </button>
                            <input 
                                type="number" 
                                value={item.stock || ''} 
                                onChange={e => handleInventoryChange(index, 'stock', Number(e.target.value))} 
                                required 
                                className="text-center w-full p-2 bg-transparent dark:text-white focus:outline-none" 
                                min="0" 
                                placeholder="الكمية"
                            />
                            <button type="button" onClick={() => handleQuantityChange(index, -1)} className="p-2 text-primary dark:text-primary-light hover:bg-primary-light dark:hover:bg-primary/20">
                                <MinusIcon className="w-5 h-5"/>
                            </button>
                          </div>

                           <input type="text" placeholder="القياس (S, 42...)" value={item.size} onChange={e => handleInventoryChange(index, 'size', e.target.value)} required className="w-1/2 p-2 border dark:border-gray-700 rounded-lg text-right bg-white dark:bg-gray-800 dark:text-white" />
                      </div>
                  ))}
               </div>
               <button type="button" onClick={addInventoryItem} className="mt-3 text-sm text-primary font-semibold flex items-center gap-1 justify-end w-full">
                    <PlusIcon className="w-4 h-4"/> إضافة قياس آخر
               </button>
            </div>
        ) : (
            // --- Series Inventory ---
            <div className="p-4 bg-blue-50 dark:bg-blue-900/10 rounded-xl border border-blue-200 dark:border-blue-800 mx-4">
               <div className="flex justify-between items-center mb-3">
                   <label className="text-sm font-bold text-blue-800 dark:text-blue-300">تفاصيل السيرية</label>
                   <CubesStackIcon className="w-5 h-5 text-blue-500" />
               </div>

               <div className="space-y-4">
                   <div>
                       <label className="text-xs font-bold text-gray-600 dark:text-gray-400 block text-right mb-1">وصف القياسات داخل السيرية</label>
                       <input 
                           type="text" 
                           placeholder="مثال: S, M, L, XL, XXL" 
                           value={seriesSizes} 
                           onChange={e => setSeriesSizes(e.target.value)} 
                           className="w-full p-3 border border-blue-200 dark:border-blue-800 rounded-lg text-right bg-white dark:bg-gray-800 dark:text-white" 
                       />
                   </div>

                   <div className="grid grid-cols-2 gap-4">
                       <div>
                           <label className="text-xs font-bold text-gray-600 dark:text-gray-400 block text-right mb-1">عدد القطع في السيرية</label>
                           <input 
                               type="number" 
                               value={seriesCount || ''} 
                               onChange={e => setSeriesCount(Number(e.target.value))} 
                               className="w-full p-3 border border-blue-200 dark:border-blue-800 rounded-lg text-center bg-white dark:bg-gray-800 dark:text-white font-bold" 
                               min="1"
                           />
                       </div>
                       <div>
                           <label className="text-xs font-bold text-gray-600 dark:text-gray-400 block text-right mb-1">عدد السيريات المتوفرة (المخزون)</label>
                           <input 
