        if (newPass.length < 6) {
            alert('كلمة المرور الجديدة يجب أن تكون 6 أحرف على الأقل');
            return;
        }
        if (newPass !== confirmPass) {
            alert('كلمات المرور الجديدة غير متطابقة');
            return;
