    onAddCustomer: (customer: Omit<Customer, 'id' | 'user_id'>) => Customer;
    onUpdateCustomer: (customer: Customer) => void;
    onDeleteCustomer: (customerId: string) => void;
    onAddProduct: (newProductData: Omit<Product, 'id'>) => void;
