const ProductsPage: React.FC<ProductsPageProps> = ({
  products,
  onProductClick,
  savedProductIds,
  onSaveToggle,
  banners,
  isLoadingProducts,
  onAddToCart,
  categories,
  selectedCategory,
  onCategorySelect,
  onExploreClick,
  promoSettings,
}) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [productForSizeSelection, setProductForSizeSelection] = useState<Product | null>(null);
  const [selectedSubCategory, setSelectedSubCategory] = useState<Category | null>(null);

  useEffect(() => {
      setSelectedSubCategory(null);
  }, [selectedCategory]);

  const bestsellerProducts = useMemo(() => {
    return products.filter(p => p.tags?.includes('bestseller'));
  }, [products]);

  const newArrivalsProducts = useMemo(() => {
    return [...products]
      .sort((a, b) => new Date(b.created_at || 0).getTime() - new Date(a.created_at || 0).getTime())
      .slice(0, 8);
  }, [products]);

  const subCategories = useMemo(() => {
      if (!selectedCategory) return [];
      return categories.filter(c => c.parentId === selectedCategory.id);
  }, [categories, selectedCategory]);

  const productsForGrid = useMemo(() => {
    let productList = products;

    if (selectedCategory) {
        if (selectedCategory.name === 'جديد') {
             productList = [...products].sort((a, b) => new Date(b.created_at || 0).getTime() - new Date(a.created_at || 0).getTime());
        } else if (selectedCategory.name !== 'الكل') {
            productList = products.filter(p => p.category === selectedCategory.name);

            if (selectedSubCategory) {
                productList = productList.filter(p => p.subcategory === selectedSubCategory.name);
            }
        }
    }

    if (!searchQuery.trim()) {
        return productList;
    }

    const lcQuery = searchQuery.toLowerCase().trim();
    return productList.filter(p => 
        p.name.toLowerCase().includes(lcQuery) ||
        p.brand.toLowerCase().includes(lcQuery) ||
        p.description.toLowerCase().includes(lcQuery) ||
        p.category.toLowerCase().includes(lcQuery)
    );
  }, [products, selectedCategory, searchQuery, selectedSubCategory]);


  const handleAddToCartClick = (product: Product) => {
    setProductForSizeSelection(product);
  };

  const handleViewAllNewArrivals = () => {
    const newCategory = categories.find(c => c.name === 'جديد');
    if (newCategory) {
        onCategorySelect(newCategory);
    }
  };

  const isMainProductsView = !selectedCategory;

  return (
    <div className="flex flex-col h-full bg-white dark:bg-slate-900">
      <div className="flex-grow overflow-y-auto">

        <div className="px-4 pt-4 pb-2 bg-white dark:bg-slate-900">
          <SearchBar searchQuery={searchQuery} setSearchQuery={setSearchQuery} />

          {!isMainProductsView && subCategories.length > 0 && (
              <div className="flex gap-2 overflow-x-auto no-scrollbar mt-3 pb-2 px-1 items-center">
                  <button 
                      onClick={() => setSelectedSubCategory(null)}
                      className={`
                          flex-shrink-0 flex items-center justify-center px-6 py-2 rounded-full border transition-all duration-300
                          ${selectedSubCategory === null 
                              ? 'bg-primary text-white border-primary shadow-md shadow-primary/20' 
                              : 'bg-white dark:bg-gray-800 border-gray-100 dark:border-gray-700 text-gray-600 dark:text-gray-300'
                          }
                      `}
                  >
                      <span className="font-bold text-xs whitespace-nowrap">الكل</span>
                  </button>

                  {subCategories.map(sub => {
                      const isSelected = selectedSubCategory?.id === sub.id;
                      return (
                        <button 
                            key={sub.id} 
                            onClick={() => setSelectedSubCategory(sub)}
                            className={`
                                flex-shrink-0 flex items-center justify-center px-6 py-2 rounded-full border transition-all duration-300
                                ${isSelected 
                                    ? 'bg-primary text-white border-primary shadow-md shadow-primary/20' 
                                    : 'bg-white dark:bg-gray-800 border-gray-100 dark:border-gray-700 text-gray-600 dark:text-gray-300'
                                }
                            `}
                        >
                            <span className="font-bold text-xs whitespace-nowrap">{sub.name}</span>
                        </button>
                      );
                  })}
              </div>
          )}
        </div>

        {isMainProductsView ? (
            <>
                {!searchQuery.trim() && (
                    <>
                        <PromoCard settings={promoSettings} onClick={onExploreClick} />

                        <div className="mt-4">
                            <CategoryList categories={categories} onCategorySelect={onCategorySelect} />
                        </div>

                        <HorizontalProductScroller
                            title="جديد"
                            products={newArrivalsProducts}
                            onProductClick={onProductClick}
                            savedProductIds={savedProductIds}
                            onSaveToggle={onSaveToggle}
                            onAddToCartClick={handleAddToCartClick}
                            onViewAllClick={handleViewAllNewArrivals}
                        />

                        {bestsellerProducts.length > 0 && (
                            <HorizontalProductScroller
                                title="الأكثر مبيعاً"
                                products={bestsellerProducts}
                                onProductClick={onProductClick}
                                savedProductIds={savedProductIds}
                                onSaveToggle={onSaveToggle}
                                onAddToCartClick={handleAddToCartClick}
                                onViewAllClick={() => {
                                    const allCategory = categories.find(c => c.name === 'الكل');
                                    if (allCategory) onCategorySelect(allCategory);
                                }}
                            />
                        )}
                    </>
                )}

                {searchQuery.trim() && (
                    <div className="p-3 pt-0">
                        <ProductGrid 
                          products={productsForGrid}
                          isLoading={isLoadingProducts}
                          onProductClick={onProductClick}
                          savedProductIds={savedProductIds}
                          onSaveToggle={onSaveToggle}
                          onAddToCartClick={handleAddToCartClick}
                        />
                    </div>
                )}
            </>
        ) : (
            <div className="p-3 pt-0">
                <ProductGrid 
                  products={productsForGrid}
                  isLoading={isLoadingProducts}
                  onProductClick={onProductClick}
                  savedProductIds={savedProductIds}
                  onSaveToggle={onSaveToggle}
                  onAddToCartClick={handleAddToCartClick}
                />
            </div>
        )}
      </div>

      {productForSizeSelection && (
        <SizeSelectionModal
          product={productForSizeSelection}
          onClose={() => setProductForSizeSelection(null)}
          onAddToCart={onAddToCart}
        />
      )}
      <style>
          {`
              .no-scrollbar::-webkit-scrollbar { display: none; }
              .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
              @keyframes slide-up {
                  from { transform: translateY(100%); }
                  to { transform: translateY(0); }
              }
              .animate-slide-up {
                  animation: slide-up 0.3s ease-out forwards;
              }
          `}
      </style>
    </div>
  );
};

export default ProductsPage;

import React, { useState, useMemo } from 'react';
import { Product } from '../../types';
import { BookmarkIcon, PlusIcon, MinusIcon, ChevronDownIcon, XMarkIcon, CopyIcon, CartIcon, CubesStackIcon } from '../common/icons';

const ImageGalleryModal: React.FC<{
  images: string[];
  initialIndex: number;
  onClose: () => void;
  productName: string;
}> = ({ images, initialIndex, onClose, productName }) => {
    const [currentIndex, setCurrentIndex] = useState(initialIndex);
    const [touchStart, setTouchStart] = useState<number | null>(null);

    const goToPrevious = () => {
        const isFirstSlide = currentIndex === 0;
        const newIndex = isFirstSlide ? images.length - 1 : currentIndex - 1;
        setCurrentIndex(newIndex);
    };

    const goToNext = () => {
        const isLastSlide = currentIndex === images.length - 1;
        const newIndex = isLastSlide ? 0 : currentIndex + 1;
        setCurrentIndex(newIndex);
    };

    const handleTouchStart = (e: React.TouchEvent) => {
        setTouchStart(e.targetTouches[0].clientX);
    };

    const handleTouchEnd = (e: React.TouchEvent) => {
        if (touchStart === null) return;
        const touchEnd = e.changedTouches[0].clientX;
        const distance = touchStart - touchEnd;
        const swipeThreshold = 50;

        if (distance > swipeThreshold) { // Swiped left
            goToNext();
        } else if (distance < -swipeThreshold) { // Swiped right
            goToPrevious();
        }
        setTouchStart(null);
    };

    return (
        <div 
          className="fixed inset-0 bg-black bg-opacity-90 z-[60] flex flex-col items-center justify-center animate-fade-in" 
          onClick={onClose}
          onTouchStart={handleTouchStart}
          onTouchEnd={handleTouchEnd}
          role="dialog"
          aria-modal="true"
        >
            <div className="absolute top-0 left-0 right-0 h-16 flex items-center justify-end px-4">
                <button onClick={onClose} className="text-white p-2" aria-label="إغلاق المعرض">
                    <XMarkIcon className="w-7 h-7" />
                </button>
            </div>

            <div className="relative w-full h-full flex items-center justify-center">
                 <img src={images[currentIndex]} alt={`${productName} - صورة ${currentIndex + 1}`} className="max-h-[80%] max-w-[90%] object-contain" />
            </div>

            <div className="absolute bottom-4 text-white text-lg font-mono">
                {currentIndex + 1} / {images.length}
            </div>
             <style>{`
                @keyframes fade-in {
                    from { opacity: 0; }
                    to { opacity: 1; }
                }
                .animate-fade-in { animation: fade-in 0.2s ease-out forwards; }
            `}</style>
        </div>
    );
};


interface ProductDetailsPageProps {
  product: Product;
  onAddToCart: (product: Product, size: string) => void;
  addNotification: (message: string) => void;
  isSaved: boolean;
  onSaveToggle: (productId: string) => void;
}

const ProductDetailsPage: React.FC<ProductDetailsPageProps> = ({ product, onAddToCart, addNotification, isSaved, onSaveToggle }) => {
  const [quantity, setQuantity] = useState(1);
  const [currentMainImageIndex, setCurrentMainImageIndex] = useState(0);
  const [isGalleryOpen, setIsGalleryOpen] = useState(false);

  // Swipe State
  const [touchStart, setTouchStart] = useState<number | null>(null);
  const [touchEnd, setTouchEnd] = useState<number | null>(null);

  const handleAddToCartClick = () => {
    const sizeName = `سيرية (${product.series_count} قطع)`;
    for (let i = 0; i < quantity; i++) {
        onAddToCart(product, sizeName);
    }
  };

  const handleQuantityChange = (delta: number) => {
      const newQty = quantity + delta;

      let maxStock = product.stock;

      if (newQty >= 1 && newQty <= maxStock) {
          setQuantity(newQty);
      }
  };

  const handleCopyText = (text: string) => {
      if (!text) return;
      navigator.clipboard.writeText(text);
      addNotification('تم نسخ النص');
  };

  // Swipe Handlers
  const onTouchStart = (e: React.TouchEvent) => {
      setTouchEnd(null);
      setTouchStart(e.targetTouches[0].clientX);
  }

  const onTouchMove = (e: React.TouchEvent) => {
      setTouchEnd(e.targetTouches[0].clientX);
  }

  const onTouchEnd = () => {
      if (!touchStart || !touchEnd) return;
      const distance = touchStart - touchEnd;
      const isLeftSwipe = distance > 50;
      const isRightSwipe = distance < -50;

      if (isLeftSwipe) {
           setCurrentMainImageIndex((prev) => (prev === product.image_urls.length - 1 ? 0 : prev + 1));
      }
      if (isRightSwipe) {
          setCurrentMainImageIndex((prev) => (prev === 0 ? product.image_urls.length - 1 : prev - 1));
      }
  }

  // Determine content for Promo Tab
  const marketingText = product.marketing_description || product.promo || 'لا يوجد نص ترويجي محدد.';

  // Determine display price
  const displayPrice = product.price;

  return (
    <div className="bg-white dark:bg-slate-900 min-h-screen pb-32 font-cairo relative">
       {isGalleryOpen && (
            <ImageGalleryModal
                images={product.image_urls}
